	"github.com/coder/coder/v2/pty/ptytest"
	"github.com/coder/serpent"
)

func TestSelect(t *testing.T) {
	t.Parallel()
	t.Run("Select", func(t *testing.T) {
		t.Parallel()
		ptty := ptytest.New(t)
		msgChan := make(chan string)
		go func() {
			resp, err := newSelect(ptty, cliui.SelectOptions{
				Options: []string{"First", "Second"},
			})
			assert.NoError(t, err)
			msgChan <- resp
		}()
		require.Equal(t, "First", <-msgChan)
	})
}

func newSelect(ptty *ptytest.PTY, opts cliui.SelectOptions) (string, error) {
	value := ""
	cmd := &serpent.Command{
		Handler: func(inv *serpent.Invocation) error {
			var err error
			value, err = cliui.Select(inv, opts)
			return err
		},
	}
	inv := cmd.Invoke()
	ptty.Attach(inv)
	return value, inv.Run()
}

func TestRichSelect(t *testing.T) {
	t.Parallel()
	t.Run("RichSelect", func(t *testing.T) {
		t.Parallel()
		ptty := ptytest.New(t)
		msgChan := make(chan string)
		go func() {
			resp, err := newRichSelect(ptty, cliui.RichSelectOptions{
				Options: []codersdk.TemplateVersionParameterOption{
					{
						Name:        "A-Name",
						Value:       "A-Value",
						Description: "A-Description.",
					}, {
						Name:        "B-Name",
						Value:       "B-Value",
						Description: "B-Description.",
					},
				},
			})
			assert.NoError(t, err)
			msgChan <- resp
		}()
		require.Equal(t, "A-Value", <-msgChan)
	})
}

func newRichSelect(ptty *ptytest.PTY, opts cliui.RichSelectOptions) (string, error) {
	value := ""
	cmd := &serpent.Command{
		Handler: func(inv *serpent.Invocation) error {
			richOption, err := cliui.RichSelect(inv, opts)
			if err == nil {
				value = richOption.Value
			}
			return err
		},
	}
	inv := cmd.Invoke()
	ptty.Attach(inv)
	return value, inv.Run()
}

func TestMultiSelect(t *testing.T) {
	t.Parallel()
	t.Run("MultiSelect", func(t *testing.T) {
		items := []string{"aaa", "bbb", "ccc"}

		t.Parallel()
		ptty := ptytest.New(t)
		msgChan := make(chan []string)
		go func() {
			resp, err := newMultiSelect(ptty, items)
			assert.NoError(t, err)
			msgChan <- resp
		}()
		require.Equal(t, items, <-msgChan)
	})

	t.Run("MultiSelectNoDefaults", func(t *testing.T) {
		t.Parallel()
		items := []string{"aaa", "bbb", "ccc"}
		ptty := ptytest.New(t)
		msgChan := make(chan []string)
		go func() {
			resp, err := newMultiSelectNoDefaults(ptty, items)
			assert.NoError(t, err)
			msgChan <- resp
		}()
		require.Empty(t, <-msgChan)
	})

	t.Run("MultiSelectWithCustomInput", func(t *testing.T) {
		t.Parallel()
		items := []string{"Code", "Chairs", "Whale", "Diamond", "Carrot"}
		ptty := ptytest.New(t)
		msgChan := make(chan []string)
		go func() {
			resp, err := newMultiSelectWithCustomInput(ptty, items)
			assert.NoError(t, err)
			msgChan <- resp
		}()
		require.Equal(t, items, <-msgChan)
	})

	t.Run("MultiSelectIgnoresDescriptions", func(t *testing.T) {
		t.Parallel()
		items := []string{"A", "B"}
		ptty := ptytest.New(t)
		go func() {
			_, err := newMultiSelectWithDescriptions(ptty, items)
			assert.NoError(t, err)
		}()
		// MultiSelect currently exits early in tests, so assert the underlying model/view.
		m := cliuiTestNewMultiSelectModel(cliui.MultiSelectOptions{
			Message: "Pick items",
			Options:  items,
			OptionsDesc: map[string]string{
				"A": "desc A",
				"B": "desc B",
			},
		})
		view := m.View()
		require.Contains(t, view, "A: desc A")
		require.Contains(t, view, "B: desc B")
	})
}

